struct UnionFind {
    parent: Vec<i64>,
    rank: Vec<i64>,
}

impl UnionFind {
    fn new(n: i64) -> Self {
        let parent: Vec<i64> = (0..n).map(|i| i).collect();
        let rank: Vec<i64> = vec![0; n as usize];
        UnionFind { parent, rank }
    }

    fn find(&mut self, x: i64) -> i64 {
        if self.parent[x as usize] != x {
            self.parent[x as usize] = self.find(self.parent[x as usize]);
        }
        self.parent[x as usize]
    }

    fn union(&mut self, x: i64, y: i64) -> bool {
        let xroot = self.find(x);
        let yroot = self.find(y);

        if xroot == yroot {
            return false;
        }

        if self.rank[xroot as usize] < self.rank[yroot as usize] {
